import re


def abbreviate(words):
    """Return the acronym for the given phrase in uppercase.

    Hyphens are treated as word separators; all other punctuation is ignored.
    """
    tokens = re.split(r'[\s\-]+', words)
    result = []
    for token in tokens:
        for ch in token:
            if ch.isalpha():
                result.append(ch.upper())
                break
    return ''.join(result)

